#include <bits/stdc++.h>
using namespace std;
int n,edge[102],val[102];
long long dp[102][102][2];
int main(){
	scanf("%d",&n);
	for(int i=1;i<=100;i++)
		for(int j=1;j<=100;j++)
			dp[i][j][0]=-1e18;
	for(int i=1;i<=100;i++)
		for(int j=1;j<=100;j++)
			dp[i][j][1]=1e18;
	for(int i=1;i<=n;i++){
		char c;
		int x;
		cin>>c>>x;
		edge[i]=(c=='x'),val[i]=x;
		dp[i][i][0]=dp[i][i][1]=val[i];
	}
	for(int i=n+1;i<2*n;i++)
		val[i]=val[i-n],edge[i]=edge[i-n],dp[i][i][0]=dp[i][i][1]=val[i];
	for(int len=2;len<=n;len++)
		for(int l=1;l+len-1<2*n;l++){
			int r=l+len-1;
			for(int k=l;k<r;k++)
				dp[l][r][0]=max(dp[l][r][0],(edge[k+1]?max(dp[l][k][0]*dp[k+1][r][0],dp[l][k][1]*dp[k+1][r][1]):dp[l][k][0]+dp[k+1][r][0]));
			for(int k=l;k<r;k++)
				dp[l][r][1]=min(dp[l][r][1],(edge[k+1]?min(dp[l][k][0]*dp[k+1][r][0],dp[l][k][1]*dp[k+1][r][1]):dp[l][k][1]+dp[k+1][r][1]));
		}
	long long ans=-1e9;
	for(int i=1;i<=n;i++)
		ans=max(ans,dp[i][i+n-1][0]);
	printf("%lld\n",ans);
	for(int i=1;i<=n;i++)
		if(dp[i][i+n-1][0]==ans)
			printf("%d ",i);
	return 0;
}
